+            a.len() as c_int,
+        )
+    };
+    let pb = unsafe {
+        crypt_gensalt_rn(
+            prefix.as_ptr(),
+            5000,
+            rbytes.as_ptr() as *const c_char,
+            rbytes.len() as c_int,
+            b.as_mut_ptr() as *mut c_char,
+            b.len() as c_int,
+        )
+    };
+
+    assert!(!pa.is_null() && !pb.is_null());
+    assert_eq!(unsafe { CStr::from_ptr(pa) }, unsafe { CStr::from_ptr(pb) });
+}
